@@ -212,7 +212,7 @@ func (d *Daemon) ensureDeaconRunning() {

 		// Claude has exited (shell is showing) - restart it
 		d.logger.Printf("Deacon session exists but Claude exited (cmd=%s), restarting...", cmd)
